// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';
// Helper to get all IDs as Set
const makeSet = arr => new Set(arr.map(o => o.id));

const TopWorstSellers = () => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    // Initialize filters with all options checked
    const [filters, setFilters] = useState({
        segments:   makeSet(require('./Icons/optionbarOptions').segmentOptions),
        highlights: makeSet(require('./Icons/optionbarOptions').highlightOptions),
        seasons:    makeSet(require('./Icons/optionbarOptions').seasonOptions),
        locations:  makeSet(require('./Icons/optionbarOptions').locationOptions)
    });

    useEffect(() => {
        const fetchSales = async () => {
            setLoading(true);
            try {
                const res = await axios.get('http://localhost:3007/api/sales', {
                    withCredentials: true
                });
                // API should return these fields
                const mapped = res.data.map(({ item_name, sold_count, id_category, category_name, is_high_margin, is_trending, eco_friendly, season }) => ({
                    name:           item_name,
                    count:          sold_count,
                    category:       id_category,
                    categoryLabel:  category_name,
                    high_margin:    Boolean(is_high_margin),
                    trending:       Boolean(is_trending),
                    eco_friendly:   Boolean(eco_friendly),
                    season:         season || 'Unknown'
                }));
                setItems(mapped);
            } catch (e) {
                console.error(e);
                setError('Kon verkoopcijfers niet laden');
            } finally {
                setLoading(false);
            }
        };
        fetchSales();
    }, []);

    if (loading) return <p>Loading…</p>;
    if (error)   return <p className="error">{error}</p>;

    // Apply filters locally
    const filteredByOptions = items.filter(item =>
        filters.segments.has(item.category) &&
        filters.highlights.has(item.high_margin ? 1 : 0) &&
        filters.seasons.has(item.season) &&
        filters.locations.has(item.category) // adjust if location property
    );

    // Sort
    const sortedItems = [...filteredByOptions].sort((a, b) =>
        sortOrder === 'top' ? b.count - a.count : a.count - b.count
    );

    // Search
    const visible = sortedItems.filter(item =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            <Optionbar filters={filters} onChange={setFilters} />
            <div className="centre-content">
                <div className="segment-section">
                    <h2 className="section-title">Top & Worst</h2>
                </div>
                <div className="items-section">
                    <div className="list-header">
                        <div className="header-title">
                            <p>Top & Worst</p>
                            <h2 className="section-title">Cocktail-items</h2>
                        </div>
                        <div className="section-order">
                            <span
                                className={`order-button ${sortOrder === 'top' ? 'active' : ''}`}
                                onClick={() => setSortOrder('top')}
                            >Top sellers ↑</span>
                            <span
                                className={`order-button ${sortOrder === 'worst' ? 'active' : ''}`}
                                onClick={() => setSortOrder('worst')}
                            >Worst sellers ↓</span>
                        </div>
                        <div className="search-bar">
                            <input
                                type="text"
                                placeholder="Search"
                                value={searchTerm}
                                onChange={e => setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                    <ul className="items-list">
                        {visible.map((item, idx) => (
                            <li key={idx} className="item">
                                <div className="item-info">
                                    <span className="item-rank">{idx + 1}.</span>
                                    <span className="item-name">{item.name}</span>
                                </div>
                                <div className="item-details">
                                    <div className="item-tags">
                                        {item.categoryLabel && <span className="tag">{item.categoryLabel}</span>}
                                        {item.high_margin && <span className="tag">High Margin</span>}
                                        {item.trending && <span className="tag">Trending</span>}
                                        {item.eco_friendly && <span className="tag">Eco Friendly</span>}
                                        {item.season !== 'Unknown' && <span className="tag">{item.season}</span>}
                                    </div>
                                    <span className="item-count">{item.count} sold</span>
                                </div>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default TopWorstSellers;
